use std::{i64, str::FromStr, time::{Duration, Instant}};

mod order_workder;
mod trade_worker;
use chrono::{TimeZone, Utc};
use prost::Message;
use redis::AsyncCommands;
use rust_decimal::Decimal;
use sqlx::{QueryBuilder, postgres::PgPoolOptions};

use crate::{order_workder::start_order_worker, trade_worker::start_trade_worker};
// Simplified logic: Listen to Redis Trades -> Insert into TimescaleDB

pub mod exchange_proto {
    // This pulls in the code generated by build.rs in the target folder
    include!(concat!(env!("OUT_DIR"), "/exchange.rs"));
}


#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let db_url = std::env::var("DATABASE_URL").expect("DATABASE_URL must be set");
    let redis_url = std::env::var("REDIS_URL").expect("REDIS_URL must be set");
    let db_queue : &'static str = "db_processor";

    // 1. Connect to TimescaleDB
    let pool = PgPoolOptions::new()
        .max_connections(10)
        .connect(&db_url).await?;
    // RUN migrations on startup
    sqlx::migrate!("./migrations")
        .run(&pool)
        .await?;
    let client = redis::Client::open(redis_url)?;
   
    println!("🚀 Launching DB Workers...");

    let trade_handle = tokio::spawn({
        let pool = pool.clone();
        let client = client.clone();
        async move {
            if let Err(e) = start_trade_worker(pool, client).await {
                eprintln!("❌ Trade Worker Critical Error: {}", e);
            }
        }
    });

    let order_handle = tokio::spawn({
        let pool = pool.clone();
        let client = client.clone();
        async move {
            if let Err(e) = start_order_worker(pool, client).await {
                eprintln!("❌ Order Worker Critical Error: {}", e);
            }
        }
    });

    // join! will wait for both. If one panics, the other keeps running.
    let _ = tokio::join!(trade_handle, order_handle);
    Ok(())
}